function cardFromPoster(anchor, label){
  var image = anchor.querySelector('img');
  var title = clean(image && image.getAttribute('alt'));
  var href = abs(anchor.getAttribute('href'));
  if(!title || !href) return null;
  return new Data(
    req(coverFrom(image), BASE),
    title,
    '',
    label || 'Comic',
    'BatCave',
    '',
    '',
    false,
    req(href, BASE),
    false
  );
}

