  if(finished) return;
  finished = true;
  var obj = new MainPage(new MR('', 'GET', E, null), emptyExtra(), new JC(false,false,''), outputs);
  saved().textContent = JSON.stringify(obj);
  done();
}

function runMain(attempt){
  try {
    var nodes = Array.prototype.slice.call(document.querySelectorAll('a.poster.grid-item.has-overlay'));
    if(!nodes.length && attempt < 24) return setTimeout(function(){ runMain(attempt + 1); }, 400);

    var seen = {};
    var cards = [];
    nodes.forEach(function(node){
      var href = abs(node.getAttribute('href'));
      if(!href || seen[href]) return;
      seen[href] = true;
      var card = cardFromPoster(node, 'Comic');
      if(card) cards.push(card);
    });

    if(!cards.length) cards.push(errorCard('BatCave is still loading', 'Close and reopen the module to retry.'));
    var outputs = [];
    var featured = cards.slice(0, 1);
    var latest = cards.slice(1, 13);
    var popular = cards.slice(13, 25);
    var more = cards.slice(25, 49);

    if(featured.length) outputs.push(new Output('wide11','horizontal','ultraWideFull','leading',new Section('Featured Comic',true),null,featured));
    if(latest.length) outputs.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Popular Right Now',true),null,latest));
    if(popular.length) outputs.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Fresh Releases',true),null,popular));
    if(more.length) outputs.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('More From BatCave',true),null,more));
    finishMain(outputs);
  } catch(e){
    finishMain([new Output('wide6','vertical','doubletsFull','',new Section('',true),null,[errorCard('Home page error', e.message)])]);
  }
}
setTimeout(function(){ runMain(0); }, 300);

