  var items = Array.prototype.slice.call(document.querySelectorAll('.page__list li'));
  var prefix = label.toLowerCase() + ':';
  for(var i=0; i<items.length; i++){
    var text = clean(items[i].textContent);
    if(text.toLowerCase().indexOf(prefix) === 0) return clean(text.slice(prefix.length));
  }
  return '';
}
function chapterOrder(item, index){
  var title = clean(item.title_en || item.title || '');
  var issue = title.match(/(?:issue|chapter)\s*#?\s*(-?\d+(?:\.\d+)?)/i);
  if(issue) return { group:0, number:parseFloat(issue[1]), index:index };
  var annual = title.match(/annual\s*#?\s*(\d+(?:\.\d+)?)/i);
  if(annual) return { group:1, number:parseFloat(annual[1]), index:index };
  var position = Number(item.posi);
  return { group:2, number:isNaN(position) ? index : position, index:index };
