function runInfo(attempt){
  try {
    var titleNode = document.querySelector('h1');
    var data = embeddedData();
    if((!titleNode || !data || !data.chapters) && attempt < 28) return setTimeout(function(){ runInfo(attempt + 1); }, 400);

    var title = clean(titleNode && titleNode.textContent) || clean(data && data.title) || 'BatCave Comic';
    var poster = document.querySelector('.page__poster img') || document.querySelector('img[alt^="Poster for the comic"]');
    var descriptionNode = document.querySelector('.page__text.full-text') || document.querySelector('.page__text');
    var description = clean(descriptionNode && descriptionNode.textContent);
    var genreLinks = Array.prototype.slice.call(document.querySelectorAll('a[href*="/genres/"]'));
    var genreSeen = {};
    var genres = [];
    genreLinks.forEach(function(a){
      var value = clean(a.textContent);
      var key = value.toLowerCase();
      if(!value || genreSeen[key]) return;
      genreSeen[key] = true;
      genres.push(value.charAt(0).toUpperCase() + value.slice(1));
    });

    var newsId = data && data.news_id ? String(data.news_id) : '';
    var rawChapters = data && data.chapters ? data.chapters.slice() : [];
    var ordered = rawChapters.map(function(item, index){ return { item:item, key:chapterOrder(item,index) }; });
    ordered.sort(function(a,b){
      if(a.key.group !== b.key.group) return a.key.group - b.key.group;
      if(a.key.number !== b.key.number) return a.key.number - b.key.number;
      return a.key.index - b.key.index;
    });

    var chapters = ordered.map(function(row){
      var item = row.item;
      var name = clean(item.title_en || item.title) || 'Issue';
      var url = BASE + 'reader/' + newsId + '/' + item.id;
      return new Chapter(name, req(url, currentUrl()), false);
    });

    var value = new InfoOutput(
      req(coverFrom(poster), currentUrl()),
      title,
      req(currentUrl(), BASE),
      description,
      genres,
      infoValue('Release type'),
      infoValue('Year'),
      infoValue('Publisher'),
      'Issues: ' + chapters.length,
      chapters
    );
    finishInfo(value);
  } catch(e){
    finishInfo(new InfoOutput(req(ICON, BASE),'Comic info error',req(BASE,BASE),e.message,[],'','','','',[]));
  }
}
