var finished = false;

function saved(){ return document.getElementById('ketsu-final-data'); }
function done(){ try { window.webkit.messageHandlers.EXECUTE_KETSU_ASYNC.postMessage(''); } catch(e){} }
function clean(value){ return String(value || '').replace(/\s+/g, ' ').trim(); }
function abs(url){
  url = String(url || '').trim();
  if(!url) return '';
  if(url.indexOf('//') === 0) return 'https:' + url;
  if(url.charAt(0) === '/') return BASE.slice(0, -1) + url;
  return url;
}
function currentUrl(){
  try {
    var m = JSON.parse(saved().textContent || '{}');
    if(m.request && m.request.url) return m.request.url;
  } catch(e){}
  return location.href;
}
function headers(referer){
  return [
    new KV('Referer', referer || BASE),
    new KV('Accept', '*/*')
  ];
}
function req(url, referer){ return new MR(abs(url) || ICON, 'GET', headers(referer), null); }
function emptyExtra(){ return new Extra([new Commands('', E)], E); }
function coverFrom(img){
  if(!img) return ICON;
  var value = img.getAttribute('data-src') || img.getAttribute('data-lazy-src') || img.getAttribute('src') || '';
  if(value.indexOf('data:image/gif') === 0) value = img.getAttribute('data-src') || '';
  return abs(value) || ICON;
}
function embeddedData(){
  var scripts = Array.prototype.slice.call(document.scripts || []);
  var script = scripts.find(function(s){ return (s.textContent || '').indexOf('window.__DATA__') >= 0; });
  if(!script) return null;
  var text = script.textContent || '';
  var marker = text.indexOf('window.__DATA__');
  var start = text.indexOf('{', marker);
  if(start < 0) return null;
  var depth = 0;
  var quote = '';
  var escaped = false;
  for(var i=start; i<text.length; i++){
    var c = text.charAt(i);
    if(quote){
      if(escaped) escaped = false;
      else if(c === '\\') escaped = true;
      else if(c === quote) quote = '';
      continue;
    }
    if(c === '"' || c === "'"){ quote = c; continue; }
    if(c === '{') depth++;
    else if(c === '}'){
      depth--;
      if(depth === 0) return JSON.parse(text.slice(start, i + 1));
    }
  }
  return null;
}
function errorCard(title, message){
  return new Data(req(ICON, BASE), title, message || '', 'Comic', 'BatCave', '', '', false, req(BASE, BASE), false);
}

function finishChapter(images){
  if(finished) return;
  finished = true;
  var obj = new Chapters(new MR('', '', E, null), emptyExtra(), new JC(false,false,''), new ChapterOutput(null, images, null));
  saved().textContent = JSON.stringify(obj);
  done();
}

function runChapter(attempt){
  try {
    var data = embeddedData();
    if((!data || !data.images || !data.images.length) && attempt < 28) return setTimeout(function(){ runChapter(attempt + 1); }, 400);
    var referer = currentUrl();
    var images = (data.images || []).map(function(url){ return req(url, referer); });
    if(!images.length) images.push(req(ICON, BASE));
    finishChapter(images);
  } catch(e){
    finishChapter([req(ICON, BASE)]);
  }
}
setTimeout(function(){ runChapter(0); }, 300);
